  1→import { useState } from "react";
  2→import { useNavigate } from "react-router-dom";
  3→import { motion } from "motion/react";
  4→import { PageTransition } from "@/components/PageTransition/PageTransition";
  5→import { Input } from "@/components/Input/Input";
  6→import { Button } from "@/components/Button/Button";
  7→import { VideoUpload } from "@/components/VideoUpload/VideoUpload";
  8→import { useVideoUpload } from "@/hooks/useVideoUpload";
  9→import { apiFetch } from "@/lib/api";
 10→import type { Candidate } from "@rearden/types";
 11→import styles from "./Register.module.scss";
 12→
 13→export function Register() {
 14→  const navigate = useNavigate();
 15→  const { upload, uploading, progress, previewUrl } = useVideoUpload();
 16→  const [submitting, setSubmitting] = useState(false);
 17→  const [form, setForm] = useState({
 18→    name: "",
 19→    email: "",
 20→    title: "",
 21→    location: "",
 22→    bio: "",
 23→    skills: "",
 24→    experience: "",
 25→  });
 26→
 27→  const updateField = (field: string) => (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
 28→    setForm((prev) => ({ ...prev, [field]: e.target.value }));
 29→  };
 30→
 31→  const [videoUrl, setVideoUrl] = useState<string | null>(null);
 32→
 33→  const handleVideoUpload = async (file: File) => {
 34→    try {
 35→      const url = await upload(file);
 36→      setVideoUrl(url);
 37→    } catch {
 38→      // upload error handled by hook
 39→    }
 40→  };
 41→
 42→  const handleSubmit = async (e: React.FormEvent) => {
 43→    e.preventDefault();
 44→    setSubmitting(true);
 45→
 46→    try {
 47→      const response = await apiFetch<{ success: boolean; data: Candidate }>(
 48→        "/candidates",
 49→        {
 50→          method: "POST",
 51→          body: JSON.stringify({
 52→            name: form.name,
 53→            email: form.email,
 54→            title: form.title,
 55→            location: form.location,
 56→            bio: form.bio,
 57→            skills: form.skills.split(",").map((s) => s.trim()).filter(Boolean),
 58→            experience: parseInt(form.experience) || 0,
 59→            videoUrl,
 60→            availability: "immediate",
 61→          }),
 62→        }
 63→      );
 64→
 65→      navigate(`/candidate/${response.data.id}`);
 66→    } catch {
 67→      setSubmitting(false);
 68→    }
 69→  };
 70→
 71→  return (
 72→    <PageTransition>
 73→      <div className={styles.register}>
 74→        <motion.div
 75→          className={styles.header}
 76→          initial={{ opacity: 0, y: 20 }}
 77→          animate={{ opacity: 1, y: 0 }}
 78→          transition={{ duration: 0.5 }}
 79→        >
 80→          <h1 className={styles.title}>Join Rearden</h1>
 81→          <p className={styles.subtitle}>
 82→            Create your video profile and get discovered by top recruiters
 83→          </p>
 84→        </motion.div>
 85→
 86→        <motion.form
 87→          className={styles.form}
 88→          onSubmit={handleSubmit}
 89→          initial={{ opacity: 0, y: 20 }}
 90→          animate={{ opacity: 1, y: 0 }}
 91→          transition={{ duration: 0.5, delay: 0.15 }}
 92→        >
 93→          <div className={styles.formGrid}>
 94→            <Input
 95→              label="Full Name"
 96→              placeholder="John Doe"
 97→              value={form.name}
 98→              onChange={updateField("name")}
 99→            />
100→            <Input
101→              label="Email"
102→              type="email"
103→              placeholder="john@example.com"
104→              value={form.email}
105→              onChange={updateField("email")}
106→            />
107→            <Input
108→              label="Job Title"
109→              placeholder="Senior Frontend Engineer"
110→              value={form.title}
111→              onChange={updateField("title")}
112→            />
113→            <Input
114→              label="Location"
115→              placeholder="San Francisco, CA"
116→              value={form.location}
117→              onChange={updateField("location")}
118→            />
119→            <Input
120→              label="Years of Experience"
121→              type="number"
122→              placeholder="5"
123→              value={form.experience}
124→              onChange={updateField("experience")}
125→            />
126→            <Input
127→              label="Skills (comma separated)"
128→              placeholder="React, TypeScript, Node.js"
129→              value={form.skills}
130→              onChange={updateField("skills")}
131→            />
132→          </div>
133→
134→          <div className={styles.bioField}>
135→            <label className={styles.label}>Bio</label>
136→            <textarea
137→              className={styles.textarea}
138→              placeholder="Tell recruiters about yourself, your experience, and what you're looking for..."
139→              value={form.bio}
140→              onChange={updateField("bio")}
141→              rows={4}
142→            />
143→          </div>
144→
145→          <div className={styles.videoSection}>
146→            <label className={styles.label}>Video Introduction</label>
147→            <p className={styles.videoHint}>
148→              Record a 1-2 minute video introducing yourself
149→            </p>
150→            <VideoUpload
151→              onUpload={handleVideoUpload}
152→              uploading={uploading}
153→              progress={progress}
154→              previewUrl={previewUrl ?? undefined}
155→            />
156→          </div>
157→
158→          <div className={styles.actions}>
159→            <Button
160→              variant="primary"
161→              size="lg"
162→              type="submit"
163→              disabled={submitting || !form.name || !form.email}
164→            >
165→              {submitting ? "Creating Profile..." : "Create Profile"}
166→            </Button>
167→          </div>
168→        </motion.form>
169→      </div>
170→    </PageTransition>
171→  );
172→}
