  1→import { useNavigate } from "react-router-dom";
  2→import { motion } from "motion/react";
  3→import { PageTransition } from "@/components/PageTransition/PageTransition";
  4→import { SearchBar } from "@/components/SearchBar/SearchBar";
  5→import { CandidateCard } from "@/components/CandidateCard/CandidateCard";
  6→import { useSearch } from "@/hooks/useSearch";
  7→import styles from "./Search.module.scss";
  8→
  9→const containerVariants = {
 10→  hidden: {},
 11→  visible: { transition: { staggerChildren: 0.06 } },
 12→};
 13→
 14→const cardVariants = {
 15→  hidden: { opacity: 0, y: 20, scale: 0.95 },
 16→  visible: {
 17→    opacity: 1,
 18→    y: 0,
 19→    scale: 1,
 20→    transition: { type: "spring" as const, stiffness: 300, damping: 25 },
 21→  },
 22→};
 23→
 24→export function Search() {
 25→  const navigate = useNavigate();
 26→  const { query, setQuery, results, loading, error } = useSearch();
 27→
 28→  return (
 29→    <PageTransition>
 30→      <div className={styles.search}>
 31→        <div className={styles.header}>
 32→          <motion.h1
 33→            className={styles.title}
 34→            initial={{ opacity: 0, y: 20 }}
 35→            animate={{ opacity: 1, y: 0 }}
 36→            transition={{ type: "spring", stiffness: 300, damping: 30 }}
 37→          >
 38→            {query ? "Search Results" : "Discover Talent"}
 39→          </motion.h1>
 40→          <motion.p
 41→            className={styles.subtitle}
 42→            initial={{ opacity: 0 }}
 43→            animate={{ opacity: 1 }}
 44→            transition={{ type: "spring", stiffness: 300, damping: 30, delay: 0.1 }}
 45→          >
 46→            {query
 47→              ? `${results.length} candidate${results.length !== 1 ? "s" : ""} found`
 48→              : "Use AI-powered search to find your perfect candidates"}
 49→          </motion.p>
 50→        </div>
 51→
 52→        <div className={styles.searchWrapper}>
 53→          <SearchBar value={query} onChange={setQuery} loading={loading} />
 54→        </div>
 55→
 56→        {error && (
 57→          <div className={styles.error}>
 58→            <p>Something went wrong: {error}</p>
 59→          </div>
 60→        )}
 61→
 62→        {loading && results.length === 0 ? (
 63→          <div className={styles.grid}>
 64→            {Array.from({ length: 6 }).map((_, i) => (
 65→              <div key={i} className={styles.skeleton}>
 66→                <div className={styles.skeletonThumb} />
 67→                <div className={styles.skeletonContent}>
 68→                  <div className={styles.skeletonLine} style={{ width: "60%" }} />
 69→                  <div className={styles.skeletonLine} style={{ width: "40%" }} />
 70→                  <div className={styles.skeletonLine} style={{ width: "80%" }} />
 71→                </div>
 72→              </div>
 73→            ))}
 74→          </div>
 75→        ) : results.length > 0 ? (
 76→          <motion.div
 77→            className={styles.grid}
 78→            variants={containerVariants}
 79→            initial="hidden"
 80→            animate="visible"
 81→            key={query}
 82→          >
 83→            {results.map((result) => (
 84→              <motion.div key={result.candidateId} variants={cardVariants}>
 85→                <CandidateCard
 86→                  candidate={result.candidate}
 87→                  score={result.score}
 88→                  matchReason={result.matchReason}
 89→                  onClick={() => navigate(`/candidate/${result.candidateId}`)}
 90→                />
 91→              </motion.div>
 92→            ))}
 93→          </motion.div>
 94→        ) : (
 95→          !loading && (
 96→            <motion.div
 97→              className={styles.empty}
 98→              initial={{ opacity: 0 }}
 99→              animate={{ opacity: 1 }}
100→            >
101→              <svg
102→                width="64"
103→                height="64"
104→                viewBox="0 0 24 24"
105→                fill="none"
106→                stroke="currentColor"
107→                strokeWidth="1.5"
108→              >
109→                <circle cx="11" cy="11" r="8" />
110→                <path d="m21 21-4.35-4.35" />
111→              </svg>
112→              <h3>No candidates found</h3>
113→              <p>Try adjusting your search query</p>
114→            </motion.div>
115→          )
116→        )}
117→      </div>
118→    </PageTransition>
119→  );
120→}
