 1→import { useChat } from "@/contexts/ChatContext";
 2→import { ChatConversationHeader } from "./ChatConversationHeader";
 3→import { ChatMessageList } from "./ChatMessageList";
 4→import { ChatMessageInput } from "./ChatMessageInput";
 5→import { ChatEmptyState } from "./ChatEmptyState";
 6→import styles from "./ChatConversation.module.scss";
 7→
 8→export function ChatConversation() {
 9→  const { activeConversation } = useChat();
10→
11→  if (!activeConversation) {
12→    return (
13→      <div className={styles.conversation}>
14→        <ChatEmptyState />
15→      </div>
16→    );
17→  }
18→
19→  return (
20→    <div className={styles.conversation}>
21→      <ChatConversationHeader />
22→      <ChatMessageList />
23→      <ChatMessageInput />
24→    </div>
25→  );
26→}
