 1→import { useChat } from "@/contexts/ChatContext";
 2→import { ChatSearch } from "./ChatSearch";
 3→import { ChatTabBar } from "./ChatTabBar";
 4→import { ChatConversationItem } from "./ChatConversationItem";
 5→import styles from "./ChatSidebar.module.scss";
 6→
 7→export function ChatSidebar() {
 8→  const { filteredConversations, activeConversationId, openConversation } = useChat();
 9→
10→  return (
11→    <div className={styles.sidebar}>
12→      <div className={styles.header}>
13→        <h2 className={styles.title}>Messages</h2>
14→      </div>
15→      <ChatSearch />
16→      <ChatTabBar />
17→      <div className={styles.list}>
18→        {filteredConversations.map((conv) => (
19→          <ChatConversationItem
20→            key={conv.id}
21→            conversation={conv}
22→            isActive={conv.id === activeConversationId}
23→            onSelect={openConversation}
24→          />
25→        ))}
26→        {filteredConversations.length === 0 && (
27→          <p className={styles.empty}>No conversations found</p>
28→        )}
29→      </div>
30→    </div>
31→  );
32→}
