 1→import { motion } from "motion/react";
 2→import type { ReactNode } from "react";
 3→import { useSound } from "@/hooks/useSound";
 4→import styles from "./Button.module.scss";
 5→
 6→interface ButtonProps {
 7→  variant?: "primary" | "secondary" | "ghost";
 8→  size?: "sm" | "md" | "lg";
 9→  children: ReactNode;
10→  className?: string;
11→  href?: string;
12→  disabled?: boolean;
13→  onClick?: () => void;
14→  type?: "button" | "submit" | "reset";
15→}
16→
17→export function Button({
18→  variant = "primary",
19→  size = "md",
20→  children,
21→  className,
22→  href,
23→  disabled,
24→  onClick,
25→  type = "button",
26→}: ButtonProps) {
27→  const { playSound } = useSound();
28→
29→  const classNames = [
30→    styles.button,
31→    styles[variant],
32→    styles[size],
33→    className,
34→  ]
35→    .filter(Boolean)
36→    .join(" ");
37→
38→  const handleClick = () => {
39→    playSound("click");
40→    onClick?.();
41→  };
42→
43→  const motionProps = {
44→    whileHover: { scale: 1.02 },
45→    whileTap: { scale: 0.95, y: 2 },
46→    transition: { type: "spring" as const, stiffness: 400, damping: 25 },
47→  };
48→
49→  if (href) {
50→    return (
51→      <motion.a
52→        href={href}
53→        className={classNames}
54→        onClick={() => playSound("click")}
55→        {...motionProps}
56→      >
57→        {children}
58→      </motion.a>
59→    );
60→  }
61→
62→  return (
63→    <motion.button
64→      className={classNames}
65→      disabled={disabled}
66→      onClick={handleClick}
67→      type={type}
68→      {...motionProps}
69→    >
70→      {children}
71→    </motion.button>
72→  );
73→}
74→

 1→import type { ReactNode } from "react";
 2→import styles from "./Input.module.scss";
 3→
 4→interface InputProps {
 5→  label?: string;
 6→  error?: string;
 7→  icon?: ReactNode;
 8→  className?: string;
 9→  placeholder?: string;
10→  value?: string;
11→  onChange?: (e: React.ChangeEvent<HTMLInputElement>) => void;
12→  type?: string;
13→  name?: string;
14→  id?: string;
15→}
16→
17→export function Input({
18→  label,
19→  error,
20→  icon,
21→  className,
22→  placeholder,
23→  value,
24→  onChange,
25→  type = "text",
26→  name,
27→  id,
28→}: InputProps) {
29→  return (
30→    <div className={[styles.wrapper, className].filter(Boolean).join(" ")}>
31→      {label && <label className={styles.label}>{label}</label>}
32→      <div className={styles.inputWrapper}>
33→        {icon && <div className={styles.icon}>{icon}</div>}
34→        <input
35→          className={`${styles.input} ${icon ? styles.hasIcon : ""} ${error ? styles.error : ""}`}
36→          type={type}
37→          placeholder={placeholder}
38→          value={value}
39→          onChange={onChange}
40→          name={name}
41→          id={id}
42→        />
43→      </div>
44→      {error && <span className={styles.errorMessage}>{error}</span>}
45→    </div>
46→  );
47→}
