 1→import { motion } from "motion/react";
 2→import type { Candidate } from "@rearden/types";
 3→import { SkillTag } from "@/components/SkillTag/SkillTag";
 4→import { ScoreBadge } from "@/components/ScoreBadge/ScoreBadge";
 5→import styles from "./CandidateCard.module.scss";
 6→
 7→interface CandidateCardProps {
 8→  candidate: Candidate;
 9→  score?: number;
10→  matchReason?: string;
11→  onClick?: () => void;
12→}
13→
14→export function CandidateCard({
15→  candidate,
16→  score,
17→  matchReason,
18→  onClick,
19→}: CandidateCardProps) {
20→  const displaySkills = candidate.skills.slice(0, 4);
21→
22→  return (
23→    <motion.div
24→      className={styles.card}
25→      whileHover={{ y: -4 }}
26→      whileTap={{ scale: 0.98 }}
27→      transition={{ type: "spring", stiffness: 400, damping: 25 }}
28→      onClick={onClick}
29→      role={onClick ? "button" : undefined}
30→      tabIndex={onClick ? 0 : undefined}
31→    >
32→      <div className={styles.thumbnail}>
33→        {candidate.thumbnailUrl ? (
34→          <img src={candidate.thumbnailUrl} alt={candidate.name} />
35→        ) : (
36→          <div className={styles.placeholder} />
37→        )}
38→        {score !== undefined && (
39→          <div className={styles.scoreBadge}>
40→            <ScoreBadge score={score} />
41→          </div>
42→        )}
43→      </div>
44→
45→      <div className={styles.content}>
46→        <h3 className={styles.name}>{candidate.name}</h3>
47→        <p className={styles.title}>{candidate.title}</p>
48→        <p className={styles.location}>{candidate.location}</p>
49→
50→        <div className={styles.skills}>
51→          {displaySkills.map((skill) => (
52→            <SkillTag key={skill} skill={skill} size="sm" />
53→          ))}
54→        </div>
55→
56→        {matchReason && (
57→          <p className={styles.matchReason}>{matchReason}</p>
58→        )}
59→      </div>
60→    </motion.div>
61→  );
62→}
63→

 1→import { useState, useEffect } from "react";
 2→import styles from "./SearchBar.module.scss";
 3→
 4→interface SearchBarProps {
 5→  value: string;
 6→  onChange: (value: string) => void;
 7→  onSubmit?: () => void;
 8→  loading?: boolean;
 9→}
10→
11→const PLACEHOLDERS = [
12→  "Search for React developers...",
13→  "Find senior engineers in NYC...",
14→  "Looking for ML specialists...",
15→  "Discover full-stack talent...",
16→];
17→
18→export function SearchBar({ value, onChange, onSubmit, loading }: SearchBarProps) {
19→  const [placeholderIndex, setPlaceholderIndex] = useState(0);
20→
21→  useEffect(() => {
22→    const interval = setInterval(() => {
23→      setPlaceholderIndex((prev) => (prev + 1) % PLACEHOLDERS.length);
24→    }, 3000);
25→
26→    return () => clearInterval(interval);
27→  }, []);
28→
29→  const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
30→    if (e.key === "Enter" && onSubmit) {
31→      onSubmit();
32→    }
33→  };
34→
35→  return (
36→    <div className={styles.wrapper}>
37→      <div className={styles.searchBar}>
38→        <div className={styles.iconWrapper}>
39→          {loading ? (
40→            <svg className={styles.spinner} width="20" height="20" viewBox="0 0 24 24">
41→              <circle cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="3" fill="none" opacity="0.25" />
42→              <path
43→                fill="currentColor"
44→                d="M12 2a10 10 0 0 1 10 10h-3a7 7 0 0 0-7-7V2z"
45→                opacity="0.75"
46→              />
47→            </svg>
48→          ) : (
49→            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
50→              <circle cx="11" cy="11" r="8" />
51→              <path d="m21 21-4.35-4.35" />
52→            </svg>
53→          )}
54→        </div>
55→        <input
56→          type="text"
57→          className={styles.input}
58→          value={value}
59→          onChange={(e) => onChange(e.target.value)}
60→          onKeyDown={handleKeyDown}
61→          placeholder=""
62→        />
63→        {!value && (
64→          <div className={styles.placeholder} key={placeholderIndex}>
65→            {PLACEHOLDERS[placeholderIndex]}
66→          </div>
67→        )}
68→      </div>
69→    </div>
70→  );
71→}
