 9→
10→function formatDateLabel(dateStr: string): string {
11→  const date = new Date(dateStr);
12→  const now = new Date();
13→  const diff = now.getTime() - date.getTime();
14→  const days = Math.floor(diff / 86400000);
15→
16→  if (days === 0) return "Today";
17→  if (days === 1) return "Yesterday";
18→  return date.toLocaleDateString(undefined, { month: "short", day: "numeric" });
19→}
20→
21→function groupByDate(messages: ChatMessage[]): { date: string; messages: ChatMessage[] }[] {
22→  const groups: { date: string; messages: ChatMessage[] }[] = [];
23→  let currentDate = "";
24→
25→  for (const msg of messages) {
26→    const label = formatDateLabel(msg.createdAt);
27→    if (label !== currentDate) {
28→      currentDate = label;
29→      groups.push({ date: label, messages: [msg] });
30→    } else {
31→      groups[groups.length - 1]!.messages.push(msg);
32→    }
33→  }
34→
35→  return groups;
36→}
37→
38→export function ChatMessageList() {
39→  const { activeMessages, activeConversationId, typingIndicators } = useChat();
40→  const bottomRef = useRef<HTMLDivElement>(null);
41→
42→  const groups = useMemo(() => groupByDate(activeMessages), [activeMessages]);
43→
44→  const typing = typingIndicators.find(
45→    (t) => t.conversationId === activeConversationId,
46→  );
47→
48→  useEffect(() => {
49→    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
50→  }, [activeMessages.length, typing]);
51→
52→  return (
53→    <div className={styles.list}>
54→      {groups.map((group) => (
55→        <div key={group.date}>
56→          <ChatDateDivider date={group.date} />
57→          {group.messages.map((msg) => (
58→            <motion.div
59→              key={msg.id}
60→              initial={{ opacity: 0, y: 10 }}
61→              animate={{ opacity: 1, y: 0 }}
62→              transition={{ duration: 0.2 }}
63→            >
64→              <ChatMessageBubble message={msg} />
65→            </motion.div>
66→          ))}
67→        </div>
68→      ))}
69→
70→      <AnimatePresence>
71→        {typing && (
72→          <motion.div
73→            key="typing"
74→            initial={{ opacity: 0, y: 10 }}
75→            animate={{ opacity: 1, y: 0 }}
76→            exit={{ opacity: 0, y: 10 }}
77→          >
