21→    sendMessage(trimmed);
22→    setValue("");
23→    if (textareaRef.current) {
24→      textareaRef.current.style.height = "auto";
25→    }
26→  }, [value, sendMessage]);
27→
28→  const handleKeyDown = (e: KeyboardEvent) => {
29→    if (e.key === "Enter" && !e.shiftKey) {
30→      e.preventDefault();
31→      handleSend();
32→    }
33→  };
34→
35→  const isDisabled = connectionStatus === "disconnected";
36→
37→  return (
38→    <div className={styles.inputArea}>
